<script>
export default {
  name: "TagImage",
  data() {
    return {
      api_url: "https://picsum.photos/1024/768",
      url_headers: ["Access-Control-Allow-Origin: *", "mode: no-cors"],
      image_count: null,
      image_list: null,
      image_tags: ['Blades', 'Bombs', 'Bow and Arrow', 'Bullet Boxes', 'Bullet Cells', 'Full_face_hoods', 'Injectable_Drug', 'Knives', 'Military_Clothing', 'Pcp_airguns', 'Pils Drug', 'Pistols', 'Powder_Drug', 'Revolver', 'Rifles', 'Rockets', 'Seeds', 'Shotgun', 'War Accessories', 'Weapon_Cases', 'Weapon_Magazines', 'Weapon_Storage', 'Weeds'],
      image_tag: null
    };
  },
  methods: {
    getSelectedTag(index) {
      console.log("selected index is " + index);
      let selected_tag = this.image_tags[index];
      console.log("selected tag is " + selected_tag);
      this.image_tag = selected_tag;
      this.getSimilarImages(selected_tag);
      // return this.api_url;
    },
    async getSimilarImages(tag) {
      let base_url = 'http://10.100.52.103:8000/';
      let endpoint = 'images/classification';
      let api_url = base_url + endpoint + '?label=' + tag + '&num_images=' + this.image_count;
      console.log(api_url);

      const requestOptions = {
        method: "GET",
        redirect: "follow",
      };

      const response = await fetch(api_url, requestOptions);

      this.api_data = await response.json();
      console.log("API Response Status:", this.api_data);

      this.image_list = this.api_data["files"].map((file) => {
        return {
          "img_src": base_url + file,
        };
      });
    },
    async getRandomImage() {
      // let response = await fetch("https://api.api-ninjas.com/v1/randomimage?category=technology", {method: "GET", mode: "no-cors", headers: {"X-Api-Key": "53MdYc1WN6MSjm5wg+7QOA==uRs2Omvh6AMf7hIa", "Accept": "image/jpg"}})
      let response = await fetch("https://picsum.photos/500/300");
      console.log("random image fetch");
      console.log(response.url);
      let image_url = response.url;
      return image_url;
    },
    async getRandombase64Image() {
      let base64_images = [
        '',
        '',
        '',
        '',
      ];
      let random_img = base64_images[(Math.floor(Math.random() * base64_images.length))];
      return "data:image/png;base64," + random_img;
    }
  }
};
</script>

